{
  "query": [
    "Reproductive health"
  ],
  "items": [
    {
      "title": "German Family Panel (pairfam)",
      "host": "GESIS",
      "description": "Longitudinal panel study on partnership and family dynamics in Germany, including fertility intentions, pregnancy histories, birth outcomes, contraceptive practices, and related attitudes and well-being."
    },
    {
      "title": "ALLBUS – German General Social Survey (selected waves)",
      "host": "GESIS",
      "description": "Repeated cross-sectional surveys of adults in Germany. Several waves include items on abortion attitudes, family planning, fertility intentions, and gender roles relevant to reproductive health."
    },
    {
      "title": "European Values Study (EVS) – Integrated dataset",
      "host": "GESIS",
      "description": "Cross-national survey of values across Europe. Contains questions on the justifiability of abortion, views on family and childbearing, and related moral norms tied to reproductive health."
    },
    {
      "title": "ISSP – Family and Changing Gender Roles (1994/2002/2012/2019)",
      "host": "GESIS",
      "description": "International Social Survey Programme modules focusing on family and gender roles, with content on having children, division of labor, policies supporting families, and attitudes that inform reproductive decision-making."
    },
    {
      "title": "Eurobarometer – Public Health modules (selected waves)",
      "host": "GESIS",
      "description": "EU-wide surveys with health-focused modules that include topics such as sexual health and HIV/AIDS prevention, health services access, and knowledge/attitudes pertinent to reproductive health."
    },
    {
      "title": "Population Policy Acceptance Survey (PPAS) – Germany",
      "host": "GESIS",
      "description": "Survey on fertility, family formation, and attitudes toward population and family policy in Germany, covering intentions regarding childbearing, family planning, and related reproductive health considerations."
    }
  ]
}
